xpath.script:
const div = document.querySelector('input#db').parentElement.parentElement;
const select = document.getElementById('countryDB');
const input = document.getElementById('db');
const host = window.location.host;
console.log(div);

let data = [];
switch (host) {
    case 'localhost:8118':
        data = [{
            name: "🇲🇽 México",
            db: "DevIke360",
        }, {
            name: "🇨🇴 Colombia",
            db: "DevIke360-2",
        }];
        break;
    case 'devike360.alsiba.mx':
        data = [{
            name: "🇲🇽 México",
            db: "devike360",
        }, {
            name: "🇨🇴 Colombia",
            db: "devike360-col",
        }];
        break;
    case 'qaike360.alsiba.mx':
        data = [{
            name: "🇲🇽 México",
            db: "qaike360",
        }, {
            name: "🇨🇴 Colombia",
            db: "qaike360-col",
        }];
        break;
    default:
        data = [];
};

if (data.length) {
    if (div) {
        div.classList.add("d-none");
    }
    for (let option of data) {
        select.add(new Option(option.name, option.db));
    }
}

// console.log(select, input);
select.addEventListener('change', function () {
    // console.log('Nuevo valor:', input, this.value);
    input.value = this.value;
});
